24→public class ReaderPostService extends Service implements ServiceCompletionListener {
25→    private ReaderPostLogic mReaderPostLogic;
26→
27→    @Override
28→    public IBinder onBind(Intent intent) {
29→        return null;
30→    }
31→
32→    @Override
33→    public void onCreate() {
34→        super.onCreate();
35→        mReaderPostLogic = new ReaderPostLogic(this);
36→        AppLog.i(AppLog.T.READER, "reader post service > created");
37→    }
38→
39→    @Override
40→    public void onDestroy() {
41→        AppLog.i(AppLog.T.READER, "reader post service > destroyed");
42→        super.onDestroy();
43→    }
44→
45→    @Override
46→    public int onStartCommand(Intent intent, int flags, int startId) {
47→        if (intent == null) {
48→            return START_NOT_STICKY;
49→        }
50→
51→        UpdateAction action;
52→        if (intent.hasExtra(ARG_ACTION)) {
53→            action = (UpdateAction) intent.getSerializableExtra(ARG_ACTION);
54→        } else {
55→            action = UpdateAction.REQUEST_NEWER;
56→        }
57→
58→
59→        if (intent.hasExtra(ARG_TAG)) {
60→            ReaderTag tag = (ReaderTag) intent.getSerializableExtra(ARG_TAG);
61→            EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action, tag));
62→            mReaderPostLogic.performTask(null, action, tag, -1, -1);
63→        } else if (intent.hasExtra(ARG_BLOG_ID)) {
64→            long blogId = intent.getLongExtra(ARG_BLOG_ID, 0);
65→            EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
66→            mReaderPostLogic.performTask(null, action, null, blogId, -1);
67→        } else if (intent.hasExtra(ARG_FEED_ID)) {
68→            long feedId = intent.getLongExtra(ARG_FEED_ID, 0);
69→            EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
70→            mReaderPostLogic.performTask(null, action, null, -1, feedId);
71→        }
72→
73→        return START_NOT_STICKY;
74→    }
75→
76→    @Override
77→    public void onCompleted(Object companion) {
78→        stopSelf();
79→    }
80→}
