2499→    @Override
2500→    public void onPostSelected(ReaderPost post) {
2501→        if (!isAdded() || post == null) {
2502→            return;
2503→        }
2504→
2505→        AppRatingDialog.INSTANCE.incrementInteractions(
2506→                AnalyticsTracker.Stat.APP_REVIEWS_EVENT_INCREMENTED_BY_OPENING_READER_POST
2507→        );
2508→
2509→        if (post.isBookmarked) {
2510→            if (isBookmarksList()) {
2511→                mReaderTracker.trackBlog(
2512→                        AnalyticsTracker.Stat.READER_SAVED_POST_OPENED_FROM_SAVED_POST_LIST,
2513→                        post.blogId,
2514→                        post.feedId,
2515→                        post.isFollowedByCurrentUser,
2516→                        mPostAdapter.getSource()
2517→                );
2518→            } else {
2519→                mReaderTracker.trackBlog(
2520→                        AnalyticsTracker.Stat.READER_SAVED_POST_OPENED_FROM_OTHER_POST_LIST,
2521→                        post.blogId,
2522→                        post.feedId,
2523→                        post.isFollowedByCurrentUser,
2524→                        mPostAdapter.getSource()
2525→                );
2526→            }
2527→        }
2528→
2529→        // "discover" posts that highlight another post should open the original (source) post when tapped
2530→        if (post.isDiscoverPost()) {
2531→            ReaderPostDiscoverData discoverData = post.getDiscoverData();
2532→            if (discoverData != null
2533→                && discoverData.getDiscoverType() == ReaderPostDiscoverData.DiscoverType.EDITOR_PICK) {
2534→                if (discoverData.getBlogId() != 0 && discoverData.getPostId() != 0) {
2535→                    ReaderActivityLauncher.showReaderPostDetail(
2536→                            getActivity(),
2537→                            discoverData.getBlogId(),
2538→                            discoverData.getPostId());
2539→                    return;
2540→                } else if (discoverData.hasPermalink()) {
2541→                    if (mSeenUnseenWithCounterFeatureConfig.isEnabled()) {
2542→                        mViewModel.onExternalPostOpened(post);
2543→                    }
2544→                    // if we don't have a blogId/postId, we sadly resort to showing the post
2545→                    // in a WebView activity - this will happen for non-JP self-hosted
2546→                    ReaderActivityLauncher.openUrl(getActivity(), discoverData.getPermaLink());
2547→                    return;
2548→                }
2549→            }
2550→        }
2551→
2552→        // if this is a cross-post, we want to show the original post
2553→        if (post.isXpost()) {
2554→            ReaderActivityLauncher.showReaderPostDetail(getActivity(), post.xpostBlogId, post.xpostPostId);
2555→            return;
2556→        }
2557→
2558→        ReaderPostListType type = getPostListType();
2559→
2560→        switch (type) {
2561→            case TAG_FOLLOWED:
2562→                // fall through to the TAG_PREVIEW
2563→            case TAG_PREVIEW:
2564→                ReaderActivityLauncher.showReaderPostPagerForTag(
2565→                        getActivity(),
2566→                        getCurrentTag(),
2567→                        getPostListType(),
2568→                        post.blogId,
2569→                        post.postId);
2570→                break;
2571→            case BLOG_PREVIEW:
2572→                ReaderActivityLauncher.showReaderPostPagerForBlog(
2573→                        getActivity(),
2574→                        post.blogId,
2575→                        post.postId);
2576→                break;
2577→            case SEARCH_RESULTS:
2578→                mReaderTracker.trackPost(AnalyticsTracker.Stat.READER_SEARCH_RESULT_TAPPED, post);
2579→                ReaderActivityLauncher.showReaderPostDetail(getActivity(), post.blogId, post.postId);
2580→                break;
2581→        }
2582→    }
