326→    /*
327→     * returns the passed endpoint without the unnecessary path - this is
328→     * needed because as of 20-Feb-2015 the /read/menu/ call returns the
329→     * full path but we don't want to use the full path since it may change
330→     * between API versions (as it did when we moved from v1 to v1.1)
331→     *
332→     * ex: https://public-api.wordpress.com/rest/v1/read/tags/fitness/posts
333→     * becomes just read/tags/fitness/posts
334→     */
335→    private static String getRelativeEndpoint(final String endpoint) {
336→        if (endpoint != null && endpoint.startsWith("http")) {
337→            int pos = endpoint.indexOf("/read/");
338→            if (pos > -1) {
339→                return endpoint.substring(pos + 1, endpoint.length());
340→            }
341→            pos = endpoint.indexOf("/v1/");
342→            if (pos > -1) {
343→                return endpoint.substring(pos + 4, endpoint.length());
344→            }
345→        }
346→        return StringUtils.notNullStr(endpoint);
347→    }
