424→     * returns whether any of the passed posts are new or changed - used after posts are retrieved
425→     */
426→    public static ReaderActions.UpdateResult comparePosts(ReaderPostList posts) {
427→        if (posts == null || posts.size() == 0) {
428→            return ReaderActions.UpdateResult.UNCHANGED;
429→        }
430→
431→        boolean hasChanges = false;
432→        for (ReaderPost post : posts) {
433→            ReaderPost existingPost = getBlogPost(post.blogId, post.postId, true);
434→            if (existingPost == null) {
435→                return ReaderActions.UpdateResult.HAS_NEW;
436→            } else if (!hasChanges && !post.isSamePost(existingPost)) {
437→                hasChanges = true;
438→            }
439→        }
440→
441→        return (hasChanges ? ReaderActions.UpdateResult.CHANGED : ReaderActions.UpdateResult.UNCHANGED);
442→    }
